using namespace adsk::core;
using namespace adsk::fusion;

Ptr ui;

extern "C" XI_EXPORT bool run(const char* context)
{
    Ptr app = Application::get();
    if (!app)
        return false;

    ui = app->userInterface();
    if (!ui)
        return false;

    Ptr documents = app->documents();
    if (!documents)
        return false;

    Ptr doc = documents->add(DocumentTypes::FusionDesignDocumentType);
    if (!doc)
        return false;

    Ptr product = app->activeProduct();
    if (!product)
        return false;

    Ptr design = product;
    if (!design)
        return false;

    // Get the root component of the active design
    Ptr rootComp = design->rootComponent();
    if (!rootComp)
        return false;

    // Create sketch in root component
    Ptr sketches = rootComp->sketches();
    if (!sketches)
        return false;
    Ptr xz = rootComp->xZConstructionPlane();
    if (!xz)
        return false;
    Ptr sketch = sketches->add(xz);
    if (!sketch)
        return false;
    Ptr sketchPts = sketch->sketchPoints();
    if (!sketchPts)
        return false;
    Ptr point = Point3D::create(1, 0, 1);
    if (!point)
        return false;
    Ptr sketchPt = sketchPts->add(point);
    if (!sketchPt)
        return false;
    Ptr sketchCurves = sketch->sketchCurves();
    if (!sketchCurves)
        return false;
    Ptr sketchCircles = sketchCurves->sketchCircles();
    if (!sketchCircles)
        return false;
    Ptr centerPoint = Point3D::create(0, 0, 0);
    if (!centerPoint)
        return false;
    Ptr circle = sketchCircles->addByCenterRadius(centerPoint, 5.0);
    if (!circle)
        return false;

    // Get the profile defined by the circle
    Ptr profs = sketch->profiles();
    if (!profs)
        return false;
    Ptr prof = profs->item(0);
    if (!prof)
        return false;

    // Create an extrusion input and make sure it's in a new component
    Ptr feats = rootComp->features();
    if (!feats)
        return false;
    Ptr extrudes = feats->extrudeFeatures();
    if (!extrudes)
        return false;
    Ptr extInput = extrudes->createInput(prof, FeatureOperations::NewComponentFeatureOperation);
    if (!extInput)
        return false;

    // Set the extrusion input
    Ptr distance = ValueInput::createByReal(5);
    if (!distance)
        return false;
    extInput->setDistanceExtent(true, distance);
    extInput->isSolid(true);

    // Create the extrusion
    Ptr ext = extrudes->add(extInput);
    if (!ext)
        return false;

    // Get the end face of the created extrusion body
    Ptr endFaces = ext->endFaces();
    if (!endFaces)
        return false;
    Ptr endFace = endFaces->item(0);
    if (!endFace)
        return false;

    // Get the occurrence of the new component
    Ptr occs = rootComp->occurrences();
    if (!occs)
        return false;
    Ptr occ = occs->item(0);
    if (!occ)
        return false;

    // Create a new sketch in the occurrence
    Ptr sketchInOcc = sketches->add(endFace, occ);
    if (!sketchInOcc)
        return false;

    // Get the sketch curve projected to the sketch
    Ptr sketchCurvesInOcc = sketchInOcc->sketchCurves();
    if (!sketchCurvesInOcc)
        return false;
    Ptr curve = sketchCurvesInOcc->item(0);
    if (!curve)
        return false;

    // Create the first joint geometry with the sketch curve
    Ptr geo0 = JointGeometry::createByCurve(curve, JointKeyPointTypes::CenterKeyPoint);
    if (!geo0)
        return false;

    // Create the second joint geometry with sketch point
    Ptr geo1 = JointGeometry::createByPoint(sketchPt);
    if (!geo1)
        return false;

    // Create joint input
    Ptr joints = rootComp->joints();
    if (!joints)
        return false;
    Ptr jointInput = joints->createInput(geo0, geo1);
    if (!jointInput)
        return false;

    // Set the joint input
    jointInput->setAsPinSlotJointMotion(JointDirections::ZAxisJointDirection, JointDirections::XAxisJointDirection);

    // Create the joint
    Ptr joint = joints->add(jointInput);
    if (!joint)
        return false;

    Ptr pinSlotMotion = joint->jointMotion();
    if (!pinSlotMotion)
        return false;
    Ptr limits = pinSlotMotion->rotationLimits();
    if (!limits)
        return false;
    limits->isRestValueEnabled(true);
    limits->restValue(1.0);

    return true;
}
